  launcher,
  windowManager,
  chat,
  profilesRoot,
  searchUrlBase = ZALANDO_SEARCH_URL_BASE,
  maxCandidates = ZALANDO_PRODUCT_SEARCH_MAX_CANDIDATES,
  memories = [],
} = {}) {
  const normalizedIntent = normalizeZalandoProductIntent(intent);
  const normalizedMaxCandidates = normalizeMaxCandidates(maxCandidates);
  const rankingMemories = normalizeRankingMemories(memories);
  const searchUrl = createZalandoSearchUrl(normalizedIntent, searchUrlBase);
  const rawProducts =
    products ??
    (await fetchZalandoProducts({
      browserRun,
      chat,
      intent: normalizedIntent,
      launcher,
      profilesRoot,
      searchProducts,
      searchUrl,
      windowManager,
    }));

  if (!Array.isArray(rawProducts)) {
    throw new TypeError("Zalando.lv product search adapter must return an array.");
  }

  return rankZalandoProducts(rawProducts, normalizedIntent, rankingMemories)
    .slice(0, normalizedMaxCandidates)
    .map(({ candidate }) => candidate);
