353	export async function searchEnabledRetailersInParallel({
354	  context,
355	  enabledRetailers,
356	  searchTool,
357	  renderProposalCard,
358	  chat,
359	} = {}) {
360	  const retailers = normalizeEnabledRetailers(enabledRetailers);
361	  if (retailers.length === 0) {
362	    return {
363	      cards: [],
364	      confidence: 0,
365	      retailerResults: [],
366	      type: "multi_retailer_proposal",
367	    };
368	  }
369	  if (!context || typeof context !== "object" || Array.isArray(context)) {
370	    throw new TypeError("search context must be an object.");
371	  }
372	  if (!searchTool || typeof searchTool.search !== "function") {
373	    throw new TypeError("searchTool.search must be a function.");
374	  }
375	
376	  const retailerResults = await Promise.all(
377	    retailers.map(async (retailer, index) => {
378	      const result = await searchTool.search({
379	        ...context,
380	        retailer,
381	        retailerIdentifier: retailer,
382	      });
383	      const normalized = normalizeRetailerSearchResult(result, retailer, index);
384	      if (normalized.candidates.length > 0) {
385	        await publishIncrementalProposalCard({
386	          chat,
