388	          renderProposalCard,
389	          retailerResult: normalized,
390	        });
391	      }
392	      return normalized;
393	    }),
394	  );
395	
396	  const cards = assembleMultiRetailerProposal(retailerResults);
397	
398	  return {
399	    cards,
400	    confidence: cards.length === 0 ? 0 : Math.max(...cards.map((card) => card.confidence)),
401	    retailerResults,
402	    type: "multi_retailer_proposal",
403	  };
404	}
