406	export function assembleMultiRetailerProposal(retailerResults, { maxCandidatesPerRetailer = 3 } = {}) {
407	  if (!Array.isArray(retailerResults)) {
408	    throw new TypeError("retailerResults must be an array.");
409	  }
410	  const candidateLimit = normalizePositiveInteger(maxCandidatesPerRetailer, "maxCandidatesPerRetailer");
411	
412	  return retailerResults
413	    .map((result, index) => normalizeRetailerSearchResult(result, result?.retailer, index))
414	    .filter((result) => result.candidates.length > 0)
415	    .map((result) => ({
416	      ...result,
417	      candidates: result.candidates.slice(0, candidateLimit),
418	    }))
419	    .sort(
420	      (left, right) =>
421	        right.overallMatchScore - left.overallMatchScore ||
422	        right.confidence - left.confidence ||
423	        left.index - right.index,
424	    );
425	}
